#!/usr/bin/env node

/**
 * generate-test-images.mjs
 *
 * Prompt catalog for AI-generated test images of storage containers.
 * This script stores all the prompts used to generate the test image library.
 *
 * These images are generated by the AI agent using the generate_image tool
 * and then copied into public/test-images/. This script serves as:
 *   1. A reference catalog of all prompts used
 *   2. A regeneration guide for the AI agent skill
 *
 * Usage:
 *   Invoke via the "Test Image Downloader" skill, or run directly to see the catalog:
 *   node generate-test-images.mjs [--list]
 */

