// ---------------------------------------------------------------------------
// CLI
// ---------------------------------------------------------------------------

function main() {
  console.log("\n🖼️  Wot-Box Test Image Prompt Catalog");
  console.log(`   Total: ${IMAGE_PROMPTS.good.length} good + ${IMAGE_PROMPTS.bad.length} bad = ${IMAGE_PROMPTS.good.length + IMAGE_PROMPTS.bad.length} images\n`);

  console.log("── GOOD (clear, identifiable contents) ──────────────────");
  for (const img of IMAGE_PROMPTS.good) {
    console.log(`   ✅ ${img.name}: ${img.description}`);
  }

  console.log("\n── BAD (pipeline edge cases) ─────────────────────────────");
  for (const img of IMAGE_PROMPTS.bad) {
    console.log(`   ⚠️  ${img.name}: ${img.description}`);
  }

  console.log("\n💡 To regenerate images, invoke the 'Test Image Downloader' AI skill.");
  console.log("   The skill agent will use these prompts with the generate_image tool.\n");
}

main();
